import{_ as i,b as o,a as u,c as n,d as s}from"./Pagetitle.vue_vue_type_script_setup_true_lang-cb42d41a.js";import{_ as a}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-132e3759.js";import{_ as c}from"./SeihoTestLayout-0655a218.js";import{o as y,a as v,w as r,d as p,b as e}from"./app-be753fed.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-d319c726.js";const k={class:"bg-gray-100 text-gray-800 py-10"},b={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2021年度 フォームA",w={__name:"Keiri2021a",setup(T){return(m,f)=>(y(),v(c,{title:t},{default:r(()=>[p("section",k,[e(i,{title:t,description:l}),p("div",b,[e(a,{questionNumber:1,title:t,subject:l,contents:[{answer:"0.97957",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 = 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（60歳 → 65歳）","= 65歳の生存数 ÷ 60歳の生存数","= 93,054 ÷ 94,995 = 0.979567…"]},{type:"result",value:"▶ 答え 0.97957（小数第6位を四捨五入）"}]},{answer:"98,756",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「10年後に何人残るか」は、今の人数に10年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"10年後の生存者数"},{type:"formulaBlock",value:["基準年齢（40歳）の人数 × 生存率（40歳 → 50歳）","= 100,000 × 97,539 ÷ 98,768 = 98,755.6…"]},{type:"result",value:"▶ 答え 98,756（小数第1位を四捨五入）"}]},{answer:"1.12",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 = 死亡数 × 平均生存年数","平均余命 = 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["108歳：58.951 × 0.5 = 29.4755 → 29.48","109歳：25.888 × 1.5 = 38.832 → 38.83","110歳：10.1008 × 2.5 = 25.252 → 25.25","111歳：3.4515 × 3.5 = 12.08025 → 12.08","112歳：1.0162 × 4.5 = 4.5729 → 4.57","113歳：0.3155 × 5.5 = 1.73525 → 1.74"]},{type:"text",value:"② 108歳～113歳の延べ生存年数の合計"},{type:"note",value:"108歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["29.48 + 38.83 + 25.25 + 12.08 + 4.57 + 1.74 = 111.95"]},{type:"text",value:"③ 108歳の平均余命"},{type:"formulaBlock",value:["108歳～113歳の延べ生存年数の合計 ÷ 108歳の生存者数","= 111.95 ÷ 99.723","= 1.12226…"]},{type:"result",value:"▶ 答え 1.12（小数第3位を四捨五入）"}]},{answer:"776,129",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 = 保険金 × 死亡数","現価 = 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（300万円） × 死亡数（55歳）","= 3,000千円 × 260人","= 780,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","= 780,000千円 × 0.995037","= 776,128.86千円"]},{type:"result",value:"▶ 答え：776,129千円（千円未満四捨五入）"}]},{answer:"8,050",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 = 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","= 必要な現価（問４の解） ÷ 55歳の年始生存者数","= 776,129千円 ÷ 96,441人","= 8,047.70793円"]},{type:"result",value:"▶ 答え 8,050円（10円未満四捨五入）"}]}],labels:["イ","キ","ウ","コ","カ"]}),e(a,{questionNumber:6,title:t,subject:l,contents:[{answer:"6,015",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 利率)<sup>運用期間</sup>","利息 = 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：1,000,000円","月利：0.1％ = 0.001","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["= 1,000,000円 × (1 + 0.001)<sup>6</sup>","= 1,000,000円 × 1.00601502","= 1,006,015.02円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["= 1,006,015.02円 − 1,000,000円","= 6,015.02円"]},{type:"result",value:"▶ 答え 6,015円（円未満四捨五入）"}]},{answer:"1,061,646",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.2％で半年複利の場合、半年ごとに0.6％ずつ増える。5年間では半年が10回あるため、半年利率で10回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：1,000,000円","年利：1.2％","半年利率：= 1.2％ ÷ 2 = 0.6％ = 0.006","複利回数：= 5年 × 年2回 = 10回"]},{type:"formulaBlock",value:["元利合計","= 1,000,000円 × (1 + 0.006)<sup>10</sup>","= 1,000,000円 × 1.0616461","= 1,061,646.1円"]},{type:"result",value:"▶ 答え 1,061,646円（円未満四捨五入）"}]},{answer:"1.51",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 =（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["= 0.015 ÷ 4","= 0.00375"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["= (1 + 0.00375)<sup>4</sup> − 1","= 1.015084 − 1","= 0.015084 = 1.5084％"]},{type:"result",value:"▶ 答え 1.51％（小数第3位を四捨五入）"}]},{answer:"1.33",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、5年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを5年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り = (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り = 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.3％ = 0.013","投資期間：5年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["= (1 + 0.013)<sup>5</sup> − 1","= 1.066712 − 1","= 0.066712"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["= 0.066712 ÷ 5","= 0.0133424 = 1.33424％"]},{type:"result",value:"▶ 答え 1.33％（小数第3位を四捨五入）"}]},{answer:"1,941,180",questionTitle:"現在必要資金の計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"将来200万円を得るために、今いくら必要かを求める問題。将来価値がわかっているので、複利を逆算（割り戻す）して現在価値を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 = 将来価値 ÷ (1 + 利率)<sup>期間</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["将来価値：2,000,000円","年利率：1.0％ = 0.01","期間：3年"]},{type:"formulaBlock",value:["現在価値","= 2,000,000 ÷ (1 + 0.01)<sup>3</sup>","= 2,000,000 ÷ 1.030301","= 1,941,180.295…"]},{type:"result",value:"▶ 答え 1,941,180円（円未満四捨五入）"}]}],labels:["カ","ク","ウ","イ","コ"]}),e(o,{questionNumber:3,title:t,subject:l,questionTitle:"事業年度末責任準備金",contents:["未経過保険料","危険準備金","4月1日から翌年3月31日","契約月","保険リスク"],labels:["キ","イ","エ","ケ","コ"]}),e(o,{questionNumber:4,title:t,subject:l,questionTitle:"変額保険と定額保険の比較",contents:["保証はない","変動保険金額","毎日","契約者","生命保険会社"],labels:["コ","カ","キ","ケ","イ"]}),e(a,{questionNumber:21,title:t,subject:l,contents:[{answer:"1,525,697千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（41〜45歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：300万円 = 3,000千円","保険期間：5年（41〜45歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["41歳：3,000千円 × 92 × 0.995037 = 274,630千円","42歳：3,000千円 × 98 × 0.985185 = 289,644千円","43歳：3,000千円 × 102 × 0.975431 = 298,482千円","44歳：3,000千円 × 110 × 0.965773 = 318,705千円","45歳：3,000千円 × 120 × 0.956211 = 344,236千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 274,630 + 289,644 + 298,482 + 318,705 + 344,236","= 1,525,697千円"]},{type:"result",value:"▶ 答え 1,525,697千円"}]},{answer:"280,187,708千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（5年後）に生存している人に支払われる。したがって、まず 5年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 5年後の生存者数 × 保険金額 × 期末払現価率（5年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","5年後（46歳）の生存数：98,160人","5年の期末払現価率：0.951466"]},{type:"formulaBlock",value:["満期保険金の現価","= 98,160 × 3,000 × 0.951466","= 280,187,707.680千円"]},{type:"result",value:"▶ 答え 280,187,708千円（千円未満四捨五入）"}]},{answer:"7,401,075千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（41歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","41歳の生存数：98,681人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 3,000千円 ×（25 ÷ 1000）","= 3,000 × 0.025","= 75千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 75千円 × 98,681人","= 7,401,075千円"]},{type:"result",value:"▶ 答え 7,401,075千円（千円未満四捨五入）"}]},{answer:"598,850円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価=支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を、期始払として現価に直して合計する"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（41〜45歳、期始払）"},{type:"formulaBlock",value:["41歳：P × 98,681 × 1.000000 = 98,681P","42歳：P × 98,590 × 0.990099 = 97,614P","43歳：P × 98,492 × 0.980296 = 96,551P","44歳：P × 98,390 × 0.970590 = 95,496P","45歳：P × 98,279 × 0.960980 = 94,444P"]},{type:"formulaBlock",value:["収入現価の合計","= 98,681P + 97,614P + 96,551P + 95,496P + 94,444P","= 482,786P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 1,525,697千円","満期保険金の現価（問22）= 280,187,708千円","予定事業費の現価（問23）= 7,401,075千円"]},{type:"formulaBlock",value:["支出現価","= 1,525,697 + 280,187,708 + 7,401,075","= 289,114,480千円 = 289,114,480,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["収入現価 = 支出現価 より","482,786P = 289,114,480,000円","P = 289,114,480,000円 ÷ 482,786","P = 598,846…円"]},{type:"result",value:"▶ 答え 598,850円（10円未満四捨五入）"}]},{answer:"732,000円",questionTitle:"払済保険金額",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"払済保険とは、解約返戻金をもとに、同条件の養老保険を一時払で買い直すものである。したがって、解約返戻金で購入できる保険金額を比例計算で求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["払済保険金 = 解約返戻金 ×（保険金額 ÷ 一時払保険料）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["解約返戻金：572,000円","保険金額：2,000,000円","一時払保険料：1,563,720円"]},{type:"formulaBlock",value:["払済保険金","= 572,000 ×（2,000,000 ÷ 1,563,720）","= 572,000 × 1.278…","= 731,588円"]},{type:"result",value:"▶ 答え 732,000円（千円未満四捨五入）"}]}],labels:["ア","イ","ウ","イ","ア"]}),e(u,{questionNumber:26,title:t,subject:l,questionTitle:"営業保険料",contents:["正しい","大きい契約ほど割合が高く、小さい契約ほど割合が低い → 大きい契約ほど割合が低く、小さい契約ほど割合が高い","正しい"]}),e(u,{questionNumber:27,title:t,subject:l,questionTitle:"解約返戻金",contents:["告知義務違反による契約解除や減額の場合は支払われない → 支払われる","正しい","正しい"]}),e(u,{questionNumber:28,title:t,subject:l,questionTitle:"契約変更",contents:["正しい","満期時に残額を払い戻さない → 残額があれば払い戻す","正しい"]}),e(u,{questionNumber:29,title:t,subject:l,questionTitle:"剰余金の発生源",contents:["経過年数が短いと死差益が少なく、経過年数が増すと死差益が多い → 経過年数が短いと死差益が多く、経過年数が増すと死差益が少ない","正しい","正しい"]}),e(u,{questionNumber:30,title:t,subject:l,questionTitle:"団体定期保険の数理",contents:["正しい","正しい","通常保険料 → 事情に応じて特別保険料、臨時保険料、剰余金等"]}),e(n,{questionNumber:31,title:t,subject:l,items:[{questionTitle:"契約年齢",content:"保険料が高くなる → 変わらない"},{questionTitle:"平準保険料",content:"正しい"},{questionTitle:"予定利率",content:"保険金額 → 商品の特性"},{questionTitle:"分割払営業保険料",content:"正しい"},{questionTitle:"責任準備金積立根拠",content:"平準保険料方式と同様 → 平準保険料方式と異なり"},{questionTitle:"契約転換制度",content:"転換前の特別配当の権利は継承されない → 継承される"},{questionTitle:"その他の損益",content:"加算した → 除いた"},{questionTitle:"契約者配当の意義と性格",content:"正しい"},{questionTitle:"配当金支払方法",content:"支払いの対象とならない → 支払い対象"},{questionTitle:"リスクヘッジ",content:"正しい"},{questionTitle:"死亡率",label:"オ",content:""},{questionTitle:"死亡表の種類",label:"エ",content:"完全生命表"},{questionTitle:"資産の平均利回り",label:"オ",content:""},{questionTitle:"純保険料の変化",label:"イ",content:"高くなる"},{questionTitle:"保険数理の基礎",label:"ア",content:"大数"},{questionTitle:"チルメル式保険料積立金",label:"ウ",content:"貯蓄保険料"},{questionTitle:"危険保険料の計算",label:"ア",content:"危険保険金"},{questionTitle:"配当準備金繰入",label:"ア",content:"定款"},{questionTitle:"アセット・シェア方式",label:"ア",content:"保険種類別"},{questionTitle:"団体定期保険の保険料",label:"ウ",content:"純保険料率"}]})]),e(s,{"previous-route":"keiri2022c","next-route":"keiri2021b"})])]),_:1}))}};export{w as default};
